using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ───────────────────────────────────────────────────────────
// 1. GetTypeInfo<T>()  — strongly-typed, throws if not found
// ───────────────────────────────────────────────────────────
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got JsonTypeInfo<Person>  →  Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// ───────────────────────────────────────────────────────────
// 2. TryGetTypeInfo<T>()  — probe without throwing
// ───────────────────────────────────────────────────────────

// Case A: type IS resolvable
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"\nTryGetTypeInfo<Person> succeeded  →  Type = {found.Type.Name}");
else
    Console.WriteLine("\nTryGetTypeInfo<Person> returned false (unexpected)");

// Case B: type is NOT resolvable (resolver limited to Person only)
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers =
        {
            ti => { if (ti.Type != typeof(Person)) throw new NotSupportedException(); }
        }
    }
};

if (limited.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? orderInfo))
    Console.WriteLine($"TryGetTypeInfo<Order> succeeded (unexpected): {orderInfo.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Order> returned false — no metadata, no exception 👍");

